import{_ as a,o,c as i,ai as s}from"./chunks/framework.C4ntERNc.js";const u=JSON.parse('{"title":"Projects","description":"","frontmatter":{"title":"Projects","lang":"en-US","layout":"doc","outline":"deep"},"headers":[],"relativePath":"reference-manual/formal-reference/projects.md","filePath":"reference-manual/formal-reference/projects.md"}'),n={name:"reference-manual/formal-reference/projects.md"};function t(l,e,d,c,r,p){return o(),i("div",null,[...e[0]||(e[0]=[s(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /jz-hdl/reference-manual/formal-reference/projects.md for this page in Markdown format</div><h1 id="projects" tabindex="-1">Projects <a class="header-anchor" href="#projects" aria-label="Permalink to “Projects”">​</a></h1><h2 id="canonical-form" tabindex="-1">Canonical form <a class="header-anchor" href="#canonical-form" aria-label="Permalink to “Canonical form”">​</a></h2><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>@project(CHIP=&lt;chipid&gt;) &lt;project_name&gt;</span></span>
<span class="line"><span>  @import &quot;...&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  CONFIG { ... }</span></span>
<span class="line"><span>  CLOCKS { ... }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  CLOCK_GEN { ... }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  IN_PINS { ... }</span></span>
<span class="line"><span>  OUT_PINS { ... }</span></span>
<span class="line"><span>  INOUT_PINS { ... }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  MAP { ... }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  BUS &lt;bus_id&gt; { ... }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  @blackbox &lt;name&gt; { PORT { ... } }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  @global &lt;name&gt;</span></span>
<span class="line"><span>    ...</span></span>
<span class="line"><span>  @endglob</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  @top &lt;module_name&gt; { ... }</span></span>
<span class="line"><span>@endproj</span></span></code></pre></div><h2 id="project-header" tabindex="-1">@project header <a class="header-anchor" href="#project-header" aria-label="Permalink to “@project header”">​</a></h2><ul><li><code>CHIP=chipid</code> is optional; defaults to &quot;GENERIC&quot;.</li><li>The chip ID is case-insensitive. May be an identifier or string literal.</li><li>If CHIP is not &quot;GENERIC&quot;, the compiler loads the corresponding <code>.json</code> file for chip-specific validation (memory configs, PLL definitions, etc.).</li></ul><h2 id="import" tabindex="-1">@import <a class="header-anchor" href="#import" aria-label="Permalink to “@import”">​</a></h2><ul><li>Must appear immediately after <code>@project</code> header, before CONFIG/CLOCKS/PIN blocks.</li><li>Paths are normalized; duplicate imports (same resolved path) are compile errors.</li><li>Imported files must not contain <code>@project</code>/<code>@endproj</code>.</li><li>All imported module and blackbox names share the project-wide namespace (must be unique).</li></ul><h3 id="path-normalization" tabindex="-1">Path normalization <a class="header-anchor" href="#path-normalization" aria-label="Permalink to “Path normalization”">​</a></h3><p>Import path normalization uses the operating system&#39;s canonical path resolution (POSIX <code>realpath</code>, Windows <code>_fullpath</code>). This resolves all symbolic links, eliminates <code>.</code> and <code>..</code> components, and removes redundant separators.</p><ul><li>On case-insensitive filesystems (e.g., macOS HFS+/APFS default), canonical resolution normalizes case so that <code>&quot;Foo.jz&quot;</code> and <code>&quot;foo.jz&quot;</code> are correctly identified as the same file for dedup purposes.</li><li>If the target file does not yet exist (e.g., generated source), the compiler falls back to textual normalization (collapsing <code>.</code>, <code>..</code>, and <code>//</code>) without filesystem access.</li><li>Diagnostic messages report the <strong>original user-supplied path</strong> from the <code>@import</code> directive, not the resolved canonical path.</li><li>Nested imports (imports within imported files) use the same normalization and security policy as top-level imports. The imported file&#39;s sub-parser inherits the parent&#39;s diagnostic context.</li></ul><h3 id="path-security-sandbox" tabindex="-1">Path security (sandbox) <a class="header-anchor" href="#path-security-sandbox" aria-label="Permalink to “Path security (sandbox)”">​</a></h3><p>All user-specified file paths — <code>@import</code> directives, <code>@file()</code> MEM initializers, and external chip JSON references — are subject to a sandboxing policy that restricts filesystem access to permitted root directories.</p><p><strong>Default sandbox root:</strong> The directory containing the input file (project file or standalone module file).</p><p><strong>Restrictions (enforced by default):</strong></p><table tabindex="0"><thead><tr><th>Rule ID</th><th>Condition</th><th>Error</th></tr></thead><tbody><tr><td><code>PATH_ABSOLUTE_FORBIDDEN</code></td><td>Path begins with <code>/</code> (or drive letter on Windows)</td><td>Absolute paths are forbidden unless <code>--allow-absolute-paths</code> is passed</td></tr><tr><td><code>PATH_TRAVERSAL_FORBIDDEN</code></td><td>Path contains <code>..</code> component</td><td>Directory traversal is forbidden unless <code>--allow-traversal</code> is passed</td></tr><tr><td><code>PATH_OUTSIDE_SANDBOX</code></td><td>Resolved canonical path does not start with any permitted sandbox root</td><td>File is outside all permitted directories</td></tr><tr><td><code>PATH_SYMLINK_ESCAPE</code></td><td>Symlink inside the sandbox targets a file outside the sandbox</td><td>Symlink used to escape sandbox boundary</td></tr></tbody></table><p><strong>CLI flags:</strong></p><table tabindex="0"><thead><tr><th>Flag</th><th>Effect</th></tr></thead><tbody><tr><td><code>--sandbox-root=&lt;dir&gt;</code></td><td>Add an additional permitted root directory. May be specified multiple times.</td></tr><tr><td><code>--allow-absolute-paths</code></td><td>Disable <code>PATH_ABSOLUTE_FORBIDDEN</code>. Sandbox root check still applies.</td></tr><tr><td><code>--allow-traversal</code></td><td>Disable <code>PATH_TRAVERSAL_FORBIDDEN</code>. Sandbox root check still applies.</td></tr></tbody></table><p><strong>Scope:</strong> Built-in chip data (embedded in the compiler binary) is exempt from path validation.</p><h2 id="config" tabindex="-1">CONFIG <a class="header-anchor" href="#config" aria-label="Permalink to “CONFIG”">​</a></h2><ul><li>Project-wide compile-time values referenced as <code>CONFIG.NAME</code>.</li><li>Numeric entries: integers used in compile-time contexts (widths, MEM dimensions, OVERRIDE, etc.).</li><li>String entries: double-quoted strings used in string contexts (e.g., <code>@file(CONFIG.NAME)</code> paths).</li><li>Not usable as runtime values in ASYNCHRONOUS/SYNCHRONOUS expressions.</li><li>Forward references between CONFIG entries are errors.</li><li>Type mismatch (string in numeric context or vice versa) is a compile error.</li><li>To use constants at runtime, use <code>@global</code> or <code>lit(width, value)</code>.</li></ul><h2 id="clocks" tabindex="-1">CLOCKS <a class="header-anchor" href="#clocks" aria-label="Permalink to “CLOCKS”">​</a></h2><ul><li>Declares timing constraints for named clocks.</li><li><code>period</code> is in nanoseconds; required for external IN_PIN clocks, forbidden for CLOCK_GEN-driven clocks.</li><li><code>edge</code> is Rising (default) or Falling.</li><li>Clock pins must be declared in IN_PINS (or generated by CLOCK_GEN) and have width <code>[1]</code>.</li></ul><h2 id="clock-gen" tabindex="-1">CLOCK_GEN <a class="header-anchor" href="#clock-gen" aria-label="Permalink to “CLOCK_GEN”">​</a></h2><ul><li>Declares on-chip clock generators (PLL, DLL, CLKDIV, OSC, BUF, or numbered variants like PLL2).</li><li><code>&lt;gen_type&gt;</code> is one of: <code>PLL</code>, <code>DLL</code>, <code>CLKDIV</code>, <code>OSC</code>, <code>BUF</code>, or a numbered variant (e.g., <code>PLL2</code>).</li><li>Input clock must have a period in CLOCKS (or be driven by a prior generator in the same block).</li><li>Output clocks must not have a period in CLOCKS (derived automatically).</li><li>Parameters are chip-specific and validated against chip data. Integer parameters reject decimal values; double parameters accept both.</li><li>A single CLOCK_GEN block may contain multiple generators for chaining (e.g., PLL + CLKDIV).</li><li>CLOCK_GEN chaining is permitted only if explicitly supported by the project <code>CHIP</code>.</li></ul><h3 id="generator-types" tabindex="-1">Generator types <a class="header-anchor" href="#generator-types" aria-label="Permalink to “Generator types”">​</a></h3><ul><li><strong>PLL</strong>: Frequency synthesis with VCO, feedback divider, and multiple outputs (BASE, PHASE, DIV, DIV3). Numbered variants (e.g., <strong>PLL2</strong>) represent alternate PLL implementations on the same chip with different capabilities (e.g., fractional dividers).</li><li><strong>DLL</strong>: Phase alignment without frequency multiplication. Used for clock de-skew.</li><li><strong>CLKDIV</strong>: Simple fixed-ratio frequency division. No VCO or feedback — simpler and lower-power than PLL. Produces a single BASE output. The <code>MODE</code> CONFIG parameter selects the chip-specific variant (e.g., <code>local</code> for IO-logic dividers, <code>global</code> for fabric-wide dividers).</li><li><strong>OSC</strong>: On-chip RC oscillator that generates a clock without any external reference. Does not require an IN clock. The output frequency is determined by chip-specific CONFIG parameters (e.g., <code>FREQ_DIV</code>, <code>DEVICE</code>). Produces a single BASE output.</li><li><strong>BUF</strong>: Clock buffer. Routes an input clock onto a global clock network without frequency change.</li></ul><h3 id="osc-example" tabindex="-1">OSC example <a class="header-anchor" href="#osc-example" aria-label="Permalink to “OSC example”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>CLOCK_GEN {</span></span>
<span class="line"><span>    OSC {</span></span>
<span class="line"><span>        OUT BASE osc_clk;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        CONFIG {</span></span>
<span class="line"><span>            FREQ_DIV = 10;</span></span>
<span class="line"><span>        };</span></span>
<span class="line"><span>    };</span></span>
<span class="line"><span>}</span></span></code></pre></div><h2 id="pin-blocks" tabindex="-1">PIN blocks <a class="header-anchor" href="#pin-blocks" aria-label="Permalink to “PIN blocks”">​</a></h2><ul><li><code>IN_PINS</code>, <code>OUT_PINS</code>, <code>INOUT_PINS</code> declare the physical pins and electrical config.</li><li><code>standard</code> required for all pins. Accepted single-ended standards: <code>LVTTL</code>, <code>LVCMOS33</code>, <code>LVCMOS25</code>, <code>LVCMOS18</code>, <code>LVCMOS15</code>, <code>LVCMOS12</code>, <code>PCI33</code>, <code>SSTL25_I</code>, <code>SSTL25_II</code>, <code>SSTL18_I</code>, <code>SSTL18_II</code>, <code>SSTL15</code>, <code>SSTL135</code>, <code>HSTL18_I</code>, <code>HSTL18_II</code>, <code>HSTL15_I</code>, <code>HSTL15_II</code>. Accepted differential standards: <code>LVDS25</code>, <code>LVDS33</code>, <code>BLVDS25</code>, <code>EXT_LVDS25</code>, <code>TMDS33</code>, <code>RSDS</code>, <code>MINI_LVDS</code>, <code>PPDS</code>, <code>SUB_LVDS</code>, <code>SLVS</code>, <code>LVPECL33</code>, <code>DIFF_SSTL25_I</code>, <code>DIFF_SSTL25_II</code>, <code>DIFF_SSTL18_I</code>, <code>DIFF_SSTL18_II</code>, <code>DIFF_SSTL15</code>, <code>DIFF_SSTL135</code>, <code>DIFF_HSTL18_I</code>, <code>DIFF_HSTL18_II</code>, <code>DIFF_HSTL15_I</code>, <code>DIFF_HSTL15_II</code>.</li><li><code>drive</code> required for OUT and INOUT pins (milliamps, may be fractional e.g. <code>3.5</code>).</li><li><code>mode</code> optional: <code>SINGLE</code> (default) or <code>DIFFERENTIAL</code>. Must be consistent with standard.</li><li><code>term</code> optional: <code>ON</code> or <code>OFF</code> (default <code>OFF</code>). Valid for <code>mode=DIFFERENTIAL</code> and single-ended SSTL/HSTL standards.</li><li><code>pull</code> optional: <code>UP</code>, <code>DOWN</code>, or <code>NONE</code> (default <code>NONE</code>). Not valid on <code>OUT_PINS</code>.</li><li>All declared pins must be mapped in <code>MAP</code>.</li><li>Pin names must be unique across all PIN blocks.</li></ul><h2 id="map" tabindex="-1">MAP <a class="header-anchor" href="#map" aria-label="Permalink to “MAP”">​</a></h2><ul><li>Binds top-level ports to physical pins (per-bit mapping for buses).</li><li>Every declared pin must have a MAP entry; unmapped pins are compile errors.</li><li>Every MAP entry must reference a declared pin.</li><li>Single-ended pins use scalar syntax: <code>pin = &lt;id&gt;;</code></li><li>Differential pins (<code>mode=DIFFERENTIAL</code>) use pair syntax: <code>pin = { P=&lt;id&gt;, N=&lt;id&gt; };</code></li><li>Both P and N physical pin IDs are checked for duplicate location conflicts.</li></ul><h2 id="bus-aggregation" tabindex="-1">BUS aggregation <a class="header-anchor" href="#bus-aggregation" aria-label="Permalink to “BUS aggregation”">​</a></h2><ul><li>Project-level BUS definitions define grouped signals and directions from the SOURCE perspective.</li><li>Module BUS ports refer to these definitions with a role (SOURCE or TARGET).</li><li>TARGET role flips IN/OUT directions; INOUT remains unchanged.</li></ul><h2 id="blackbox" tabindex="-1">@blackbox <a class="header-anchor" href="#blackbox" aria-label="Permalink to “@blackbox”">​</a></h2><ul><li>Declares an opaque module inside a project (PORT block only, no body).</li><li>Name shares the project-wide module namespace (must be unique).</li><li>Instantiated from modules via <code>@new</code> like regular modules.</li><li>OVERRIDE is a passthrough to the vendor module (not validated).</li><li>Blackboxes may contain <code>CONST</code> blocks (e.g., <code>CONST { FREQ_MHZ = 100; }</code>). CONST within blackboxes is a passthrough to the vendor module and is not validated by the compiler.</li></ul><h2 id="global" tabindex="-1">@global <a class="header-anchor" href="#global" aria-label="Permalink to “@global”">​</a></h2><ul><li>Defines named, sized literal constants usable as runtime values.</li><li>Constants are referenced as <code>global_name.CONST_ID</code>.</li><li>Unlike CONFIG/CONST, global constants are values (usable in expressions).</li></ul><h2 id="top" tabindex="-1">@top <a class="header-anchor" href="#top" aria-label="Permalink to “@top”">​</a></h2><ul><li>Sets the top-level module for the project.</li><li>Binds top module ports to pin names, <code>_</code> (no-connect), or bitwise pin expressions.</li><li>Pin expressions (<code>pin_expr</code>) may be a single pin name, a concatenation of pins (<code>{ pin1, pin2 }</code>), or a bitwise expression composed of declared pins (e.g., <code>{ btn1, ~btn1 }</code>).</li><li>All module ports must be listed (omission is a compile error).</li><li>Port widths must match module definition exactly.</li><li>Port direction must be compatible with pin category (IN -&gt; IN_PINS/INOUT_PINS, OUT -&gt; OUT_PINS/INOUT_PINS, INOUT -&gt; INOUT_PINS).</li><li>Module OUT ports may not be bound to literal values.</li></ul><h2 id="check" tabindex="-1">@check <a class="header-anchor" href="#check" aria-label="Permalink to “@check”">​</a></h2><ul><li>Compile-time assertion: <code>@check (expr, &quot;message&quot;);</code></li><li>Expression must be a compile-time constant; zero triggers a compile error.</li><li>Valid inside <code>@project</code> and <code>@module</code>, not inside blocks.</li></ul><h2 id="scope-and-uniqueness" tabindex="-1">Scope and uniqueness <a class="header-anchor" href="#scope-and-uniqueness" aria-label="Permalink to “Scope and uniqueness”">​</a></h2><ul><li>One <code>@project</code> per design unit.</li><li>All names in project scope (modules, blackboxes, globals, configs, pins) are unique.</li></ul>`,45)])])}const m=a(n,[["render",t]]);export{u as __pageData,m as default};
